1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const basePremiumFor = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
19	
20	const premiumFor = (items: Item[]): number => {
21	  const basePremium = basePremiumFor(items);
22	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
23	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
24	};
25	
26	const quoteStep = ({ items }: Step) => ({ premium: premiumFor(items) });
27	
28	export const runScenario = (input: Scenario): unknown => ({
29	  results: input.steps.map(quoteStep),
30	});
